sys_script_client.script:
// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
function onSubmit() {
	// STRY0076619 - Task Form - TASK ORDER Field filter on New Subtask form and prompt for user on Save.
	if(g_form.getValue('active')){
		// only check active order if the task is still active
		// Only check the order if the order is less than the Max order
		if(parseInt(g_form.getValue('task_order')) < parseInt(g_scratchpad.maxTaskOrder)){
			var ajax  = new GlideAjax('ClientTaskInfo');
			ajax.addParam('sysparm_name', 'checkActiveOrderOfParent');
			ajax.addParam('sysparm_task_parent', g_form.getValue('parent'));
			ajax.addParam('sysparm_order', g_form.getValue('task_order'));
			ajax.getXML(function(response){
				try{
					var data = response.responseXML.documentElement.getAttribute("answer");
					var msg;
					if(data == 'true'){
						msg = "All of the tasks in the Task Order selected have been completed.  Please select a higher task order.";
						g_form.showFieldMsg("task_order", msg, "error", false);
						g_form.addErrorMessage(msg);
						// NOTE this doesn't stop the submission.
						return false;
					}
				}catch(e){
					jslog (e);
				}
			});
		}

	}


}
